function checkToken(t){
	const {java,source} = this;
	t = String(t).trim();
	if(/^\d+_[a-zA-Z\d]{32}$/.test(t)){
		source.putLoginHeader(t);
		java.longToast("✅登录成功");
		}else{
			java.toast("❌token输入有误，形如 230484_ahshxbh3oAjjdjxbjsnxxxxxx");

			}
	}

function getToken(){
	const { source} = this;
    let infomap = String(source.getLoginHeader());
    infomap = (infomap!="null"&&infomap!=""&&infomap!=null)?infomap:"";
    return infomap
	}

function getImage(replyTotal,novelId,chapterId,commentId){
	let {cache} = this;
	let d = String(Date.now()).replace(/^\d{6}/,'');
  return `<img src="data:image/svg+xml;base64,,{\"type\":\"jjreply\",\"js\":\"getSvg(${replyTotal},${novelId},${chapterId}, ${commentId},${d})\"}">`;
}

function getSvg(replyTotal,novelId,chapterId,commentId,date) {
   let {java,cache,result} = this;
   let memoryKey = "jjreply"+novelId+chapterId+commentId;
   let Memory = String(cache.getFromMemory(memoryKey)); 
  let re = "1"+date;
  let f = Memory.includes(re);

    if (f) { 
    	let replyList = [];
    	let replyUrl = "https://android.jjwxc.net/comment/getReplyList";   
    let offset = 5;
    let limit = replyTotal;
    while(offset < replyTotal) {
        let replyBody = `versionCode=444&novelId=${novelId}&chapterId=${chapterId}&commentId=${commentId}&offset=${offset}&limit=${limit}&isBackend=2&token=${this.getToken()}`;
        let replyPost = {
            "method": "POST",
            "body": replyBody
        }
        let replyAjax = java.ajax(replyUrl+","+JSON.stringify(replyPost));

        replyList =replyList.concat(JSON.parse(replyAjax).data);     

        offset += limit;     
        if(offset >= replyTotal) {
            break;
        }
    }
    let html = `<meta name="viewport" content="width=device-width,initial-scale=1.0"><div class='reply-container'>`;

for (let i = 0; i < replyList.length; i++) {
    let reply = replyList[i];
    let authorTag = (reply?.isAuthor === "1" ? "👑" : "📜") +'<span class="floor">'+ (reply.floor || "") + "楼 </span>";

    let date = (!reply.comment_date_time ? undefined : java.timeFormat(reply.comment_date_time * 1000)) ?? 
               (reply.replyDate || reply.commentdate);

    let author = reply.replyAuthor ?? reply.commentauthor;


    let content = replaceEmoticons(reply.replyBody ?? reply.commentbody).replace(/&lt;/g,'<').replace(/&gt;/g,'>');

    html += `
        <div class='reply-item'>
            <div class='reply-header'>
                <span class='author-tag'>${authorTag}</span>
                <span class='author-name'>${author}</span>
                <span class='reply-date'>(${date})</span>
            </div>
            <div class='reply-content'>${content}</div>
        </div>
    `;
}

html += "</div>";

html += `
<style>
.reply-container {
    font-family: Arial, sans-serif;
    margin: 10px;
    padding: 10px;
    border: 1px solid #eee;
    border-radius: 5px;
}

.reply-item {
    margin-bottom: 15px;
