if(/chapterList/.test(baseUrl)){
let sss = String(source.getVariable());
let limit = sss.match(/◎(\d+)/)?.[1] ?? 500;
let nid = java.getString("$.novelid");
let cid = java.getString("$.chapterid");
let 点赞url = 
`https://android.jjwxc.net/comment/getCommentList?versionCode=439&limit=${limit}&offset=0&commentSort=2&token=${getToken()}&novelId=${nid}&chapterId=${cid}`;

let 回复url = `https://android.jjwxc.net/comment/getCommentList?versionCode=439&limit=${limit}&offset=0&commentSort=0&token=${getToken()}&novelId=${nid}&chapterId=${cid}`;

let 长评url = `https://android.jjwxc.net/comment/getLongCommentList`;
    let 长评option = {
	    "method":"POST", 	"body":`versionCode=439&limit=${limit}&offset=0&token=&novelId=${nid}&chapterId=${cid}`
	}
长评url = 长评url+","+JSON.stringify(长评option);

if(/◎回复/.test(sss)){
	result = 回复url
	}else if(/◎长评/.test(sss)){
		result = 长评url
}else{
	result = 点赞url
	}
}else{
	result = java.getString("$.chapterurl")
	}

