var intlLinks = [];
var seaLinks = [];
var defaultIntlLinks = ['https://18comic.vip', 'https://18comic.ink'];
var defaultSeaLinks = ['https://jmcomic-zzz.one', 'https://jmcomic-zzz.org'];
var cachedPageHtml = null;

function extractLinks(pageHtml, blockRegex) {
    var links = [];
    if (!pageHtml) return links;
    var blockMatch = pageHtml.match(blockRegex);
    if (blockMatch && blockMatch[1]) {
        var blockContent = blockMatch[1];
        var linkMatches = blockContent.match(/<span>(.*?)<\/span>/g);
        if (linkMatches) {
            links = linkMatches.map(function(spanTag) {
                var domain = spanTag.replace(/<\/?span>/g, '').trim();
                return 'https://' + domain;
            }).filter(function(url) {
                return url !== 'https://';
            });
        }
    }
    return links;
}

var intlBlockRegex = /<div class="international">([\s\S]*?)<\/div>/;
var seaBlockRegex = /<div class="southeast_asia">([\s\S]*?)<\/div>/;

try {
    cachedPageHtml = java.ajax('https://jmcomicqa.cc');
    intlLinks = extractLinks(cachedPageHtml, intlBlockRegex);
    seaLinks = extractLinks(cachedPageHtml, seaBlockRegex);

    if (intlLinks.length === 0) {
        java.log('未能从jmcomicqa.cc提取国际线路, 启用备用线路。');
        intlLinks = defaultIntlLinks;
    }
    if (seaLinks.length === 0) {
        java.log('未能从jmcomicqa.cc提取东南亚线路, 启用备用线路。');
        seaLinks = defaultSeaLinks;
    }
} catch (e) {
    java.log('访问jmcomicqa.cc失败, 启用备用线路: ' + e);
    intlLinks = defaultIntlLinks;
    seaLinks = defaultSeaLinks;
}

var original = {
    'url': 'https://jmcomicqa.cc',
    'name': '寿横',
    'tag': 0,
    'weekIndex': 0, 
    'shunt': 1,
    'usedIndexes': [],
    'lineType': '主线路',
    'intlLinkIndex': 0,
    'seaLinkIndex': 0
};
try {
    $$$= JSON.parse(source.getVariable());
    if ($$$ == null) {
        throw new Error();
    } else {
        if (!$$$.hasOwnProperty('usedIndexes'))$$$.usedIndexes = [];
        if (!$$$.hasOwnProperty('weekIndex')) $$$.weekIndex = 0;
        if (!$$$.hasOwnProperty('tag')) $$$.tag = 0;
        if (!$$$.hasOwnProperty('shunt')) $$$.shunt = 1; 
        if (!$$$.hasOwnProperty('lineType')) $$$.lineType = '主线路';
        if (!$$$.hasOwnProperty('intlLinkIndex')) $$$.intlLinkIndex = 0;
        if (!$$$.hasOwnProperty('seaLinkIndex')) $$$.seaLinkIndex = 0;
    };
} catch (e) {
    $$$= original;
    put($$$);
}

function put(data) {
    return source.setVariable(JSON.stringify(data, null, '\t'));
}

function n(e) {
    var n_str = '\n';
    for (var m = 1; m < e; m++) {
        n_str = n_str + '\n';
    }
    return n_str;
}

function log(e) {
    if (e == undefined) {
        return;
    }
    java.longToast(e);
}

var regexList = [
    /china"><span>(.*?)<\/span>/,
    /first_line"><span>(.*?)<\/span>/,
    /second_line"><span>(.*?)<\/span>/
];

function getRandomUnusedIndex() {
    if ($$$.usedIndexes.length === regexList.length) {
       $$$.usedIndexes = [];
    }
    var randomIndex;
    do {
        randomIndex = Math.floor(Math.random() * regexList.length);
    } while ($$$.usedIndexes.indexOf(randomIndex) !== -1);
    $$$.usedIndexes.push(randomIndex);
    put($$$);
    return randomIndex;
}

var MAX_INDEX = 210;
var MIN_INDEX = 0;

function updateIndex(newIndex) {
    if (newIndex !== $$$.weekIndex) {
        $$$.weekIndex = newIndex;
        put($$$);
        log('【索引更新】每周必看索引已更新为: ' + newIndex + n(2) + '请刷新探索页');
    } else {
        log('【提示】索引值未更改，当前值为: ' + newIndex);
    }
}

function randomWeekIndex() {
    var newIndex = Math.floor(Math.random() * (MAX_INDEX + 1));
    updateIndex(newIndex);
}

function incrementWeekIndex() {
    var newIndex = $$$.weekIndex + 1;
    if (newIndex > MAX_INDEX) {
        newIndex = MAX_INDEX;
        log('【警告】已达最大索引值: ' + MAX_INDEX);
    }
    updateIndex(newIndex);
}

function decrementWeekIndex() {
    var newIndex = $$$.weekIndex - 1;
    if (newIndex < MIN_INDEX) {
        newIndex = MIN_INDEX;
        log('【警告】已达最小索引值: ' + MIN_INDEX);
    }
    updateIndex(newIndex);
}

function resetWeekIndex() {
    updateIndex(MIN_INDEX);
}

function login() {
    var result = JSON.parse(source.getLoginInfo());
    var username = result['账号'];
    $$$.name = username;
