var cacheSaveSeconds = 7*24*60*60  // 长期缓存时间 7天
var cacheTempSeconds = 10*60*1000  // 短期缓存 10min

function cacheGetAndSet(key, supplyFunc) {
    const {java, cache} = this
    let v = cache.get(key)
    // 缓存信息错误时，保存 10min 后重新请求
    if (v && JSON.parse(v).error === true) {
        if (new Date().getTime() >= JSON.parse(v).timestamp + cacheTempSeconds) {
            cache.delete(key)
            v = cache.get(key)
        }
    }
    // 无缓存信息时，进行请求
    if (v === undefined || v === null) {
        v = supplyFunc()
        v.timestamp = new Date().getTime()
        v = JSON.stringify(v)
        cache.put(key, v, cacheSaveSeconds)
    }
    return JSON.parse(v)
}

function isHtmlString(str) {
    return str.startsWith("<!DOCTYPE html>")
}
function isJsonString(str) {
    try {
        if (typeof JSON.parse(str) === "object") return true
    } catch(e) {}
    return false
}

function isLogin() {
    const {java, cache} = this
    return !!cache.get("csfrToken")
}
function getAjaxJson(url, forceUpdate) {
    const {java, cache} = this
    let v = cache.get(url)
    if (forceUpdate || v && new Date().getTime() >= JSON.parse(v).timestamp + cacheTempSeconds) {
        cache.delete(url)
    }
    return this.cacheGetAndSet(url, () => {
        return JSON.parse(java.ajax(url))
    })
}
function getAjaxAllJson(urls, forceUpdate) {
    const {java, cache} = this
    let v = cache.get(urls)
    if (forceUpdate || v && new Date().getTime() >= JSON.parse(v).timestamp + cacheTempSeconds) {
        cache.delete(urls)
    }
    return this.cacheGetAndSet(urls, () => {
        let result = java.ajaxAll(urls).map(resp => JSON.parse(resp.body()))
        cache.put(urls, JSON.stringify(result), cacheSaveSeconds)
        for (let i in urls) cache.put(urls[i], JSON.stringify(result[i]), cacheSaveSeconds)
        return result
    })
}
function getWebviewJson(url, parseFunc) {
    const {java, cache} = this
    return this.cacheGetAndSet(url, () => {
        let html = java.webView(null, url, null)
        return JSON.parse(parseFunc(html))
    })
}

function urlIP(url) {
    const {java, cache, source} = this
    let isIPDirect
    if (source.bookSourceName.includes("备用") || source.bookSourceName.includes("漫画")) {
        isIPDirect = JSON.parse(String(source.variableComment).match(RegExp(/{([\s\S]*?)}/gm)))?.IPDirect || false
    } else {
        isIPDirect = JSON.parse(cache.get("pixivSettings")).IPDirect || false
    }

    if (isIPDirect) {
        url = url.replace("http://", "https://").replace("www.pixiv.net", "210.140.139.155")
        let headers = {
            // "User-Agent": "Mozilla/5.0 (Linux; Android 14)",
            // "X-Requested-With": "XMLHttpRequest",
            "Host": "www.pixiv.net",
            // "x-csrf-token": cache.get("csfrToken") || "",
            // "Cookie": cache.get("pixivCookie") || ""
        }
        return `${url}, ${JSON.stringify({headers: headers})}`
    }
    return url
}

