function isLegadoLYC() {
    let isLegadoLYCStatus = (typeof java.ajaxTestAll === "function")
    cache.put("isLegadoLYCStatus", isLegadoLYCStatus)
    return isLegadoLYCStatus
}

function publicFunc() {
    let u = {}, settings = {}
    // 输出书源信息
