var checkTimes = 0
var cacheSaveSeconds = 7*24*60*60  // 长期缓存时间 7天
var cacheTempSeconds = 10*60*1000  // 短期缓存 10min

function cacheGetAndSet(key, supplyFunc) {
    const {java, cache} = this
    let v = cache.get(key)
    // 缓存信息错误时，保存 10min 后重新请求
    if (v && JSON.parse(v).error === true) {
        if (new Date().getTime() >= JSON.parse(v).timestamp + cacheTempSeconds) {
            cache.delete(key)
            v = cache.get(key)
        }
    }
    // 无缓存信息时，进行请求
    if (v === undefined || v === null) {
        v = supplyFunc()
        v.timestamp = new Date().getTime()
        v = JSON.stringify(v)
        cache.put(key, v, cacheSaveSeconds)
    }
    return JSON.parse(v)
}

function putInCache(objectName, object, saveSeconds) {
    const {java, cache} = this
    if (object === undefined) object = null
    if (saveSeconds === undefined) saveSeconds = 0
    cache.put(objectName, JSON.stringify(object), saveSeconds)
}
function getFromCache(objectName) {
    const {java, cache} = this
    let object = cache.get(objectName)
    if (object === undefined) return null  // 兼容源阅
    return JSON.parse(object)
}

function putInCacheMap(mapName, mapObject, saveSeconds) {
    const {java, cache} = this
    let orderedArray = []
    mapObject.forEach((value, key) => {
        const item = {}
        item[key] = value
        orderedArray.push(item)
    })
    // [{'key1': 'value1'}, {'key2': 'value2'}]
    if (saveSeconds === undefined) saveSeconds = 0
    cache.put(mapName, JSON.stringify(orderedArray), saveSeconds)
}
function getFromCacheMap(mapName) {
    const {java, cache} = this
    let cached = cache.get(mapName)
    let newMap = new Map()
    if (cached === null || cached === undefined) {
        return newMap
    }

    let parsedData
    try {
        parsedData = JSON.parse(cached)
    } catch (e) {
        return newMap
    }

    if (Array.isArray(parsedData)) {
        parsedData.forEach(item => {
            for (let key in item) {
                newMap.set(key, item[key])
            }
        })
    } else {
        for (let key in parsedData) {
            newMap.set(key, parsedData[key])
        }
    }
    return newMap
}

function isHtmlString(str) {
    return str.startsWith("<!DOCTYPE html>")
}
function isJsonString(str) {
    try {
        if (typeof JSON.parse(str) === "object") return true
    } catch(e) {}
    return false
}

function getWebViewUA() {
    const {java, cache} = this
    let userAgent = String(java.getWebViewUA())
    if (userAgent.includes("Windows NT 10.0; Win64; x64")) {
        userAgent = "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/119.0.0.0 Mobile Safari/537.36"
    }
    // java.log(`userAgent=${userAgent}`)
    cache.put("userAgent", userAgent)
    return String(userAgent)
}
function isLogin() {
    const {java, cache} = this
    return !!cache.get("pixivCsrfToken")
}

function getAjaxJson(url, forceUpdate) {
    const {java, cache} = this
    let v = cache.get(url)
    if (forceUpdate || v && new Date().getTime() >= JSON.parse(v).timestamp + cacheTempSeconds) {
        cache.delete(url)
    }
    return this.cacheGetAndSet(url, () => {
        return JSON.parse(java.ajax(url))
    })
}
function getAjaxAllJson(urls, forceUpdate) {
    const {java, cache} = this
    let v = cache.get(urls)
    if (forceUpdate || v && new Date().getTime() >= JSON.parse(v).timestamp + cacheTempSeconds) {
        cache.delete(urls)
    }
    return this.cacheGetAndSet(urls, () => {
        let result = java.ajaxAll(urls).map(resp => JSON.parse(resp.body()))
        cache.put(urls, JSON.stringify(result), cacheSaveSeconds)
        for (let i in urls) cache.put(urls[i], JSON.stringify(result[i]), cacheSaveSeconds)
        return result
    })
}
function getIPJson(url, forceUpdate) {
    const {java, cache} = this
    url = url.replace("http://", "https://").replace("www.pixiv.net", "210.140.139.155")
    let v = cache.get(url)
    if (forceUpdate || v && new Date().getTime() >= JSON.parse(v).timestamp + cacheTempSeconds) {
        cache.delete(url)
    }
    let headers = {
        "User-Agent": "Mozilla/5.0 (Linux; Android 14)",
        "X-Requested-With": "XMLHttpRequest",
        "Host": "www.pixiv.net"
    }
    return this.cacheGetAndSet(url, () => {
        return JSON.parse(java.get(url, headers).body())
    })
}
function getWebviewJson(url, parseFunc) {
    const {java, cache} = this
    return this.cacheGetAndSet(url, () => {
        let html = java.webView(null, url, null)
        return JSON.parse(parseFunc(html))
    })
}

function urlIP(url) {
    const {java, cache, source} = this
    let isIPDirect
    if (source.bookSourceName.includes("备用") || source.bookSourceName.includes("漫画")) {
        isIPDirect = JSON.parse(String(source.variableComment).match(RegExp(/{([\s\S]*?)}/gm)))?.IPDirect || false
    } else {
        isIPDirect = JSON.parse(cache.get("pixivSettings"))?.IPDirect || false
    }

    if (isIPDirect) {
        url = url.replace("http://", "https://").replace("www.pixiv.net", "210.140.139.155")
        let headers = {
            "User-Agent": "Mozilla/5.0 (Linux; Android 14)",
            "X-Requested-With": "XMLHttpRequest",
            "Host": "www.pixiv.net",
            "x-csrf-token": cache.get("pixivCsrfToken") || "",
            "Cookie": cache.get("pixivCookie") || ""
        }
        return `${url}, ${JSON.stringify({headers: headers})}`
    }
    return url
}

