	 body = java.getString("@@.fiction-body p@html")
	 body = String(body).replace(/(webp|jpg)/g, "$1,"+headers);
} else if (/photo/.test(baseUrl)) {
  let imgs = java.getElements(".photo-image .img");
  let html = "";
	 imgs.forEach(p => {
	 	  let style = String(p.attr("style"));
	   let pic = style?.match(/http.*?(?:webp|jpg)/)?.[0] || "";
	   html += pic ? `<img src="${pic}"><br>` : "";
	 })
	 let doc = org.jsoup.Jsoup.parse(html);
	 body = doc.select("img");
	 body.forEach(p => {
	 	  let pic = String(p.attr("src"));
	 	  pic += "," + headers;
	 	  p.attr("src", pic)
	 })
} else if (/video/.test(baseUrl)) {
	 body = result?.match(/http.*?\.m3u8[^']*/)?.[0] || "";
	 if(body){
	 	  body += "," + headers;
     if (!java.openVideoPlayer) {
     	  // 原版无此方法
       // 原版：打开浏览器并返回封面图
       java.startBrowser(body, book.name);
      body = `<img src="${book.coverUrl}">`;
    };
	 	}else{
	 		 java.toast("Sorry，没有匹配到播放链接！！！")
	 }
}

body;

ruleToc.chapterList:
@js:
function getMaxPage(arr){
  return Array.from(arr).reduce((max, cur) => {
    const n = +String(cur) || 0;
    return Math.max(max, n)
  }, 1)
};

let chapters = [];
let url = baseUrl;
if(/fiction/.test(baseUrl)){
	 let id = java.get("xchinaID");
	 if(id == "998"){ //漫画小说是图片类型
	 	  book.type = 64;
	 	}else{
	   book.type = 8;
	 }
  let list = java.getElements("@@.chapter-container a");
  let size = list.size();
  if(size == 0){
    chapters.push({
	 	  	 title: java.getString("@@.title@text"),
	 	  	 url
	 	  })
  }else{
    for (let i = 0; i < size; i++) {
      let a = list.get(i);
      chapters.push({
        title: a.text(),
        url:   a.attr('href')
      });
    }
  }
}else if(/photo/.test(baseUrl)){
	 book.type = 64;
	 let pages = java.getStringList("@css:.pager a@text");
	 let max = getMaxPage(pages);
	 if(max == 1) {
	 	  chapters.push({
	 	  	 title: book.name,
	 	  	 url
	 	  })
	 	}else{
	 		chapters.push({
	 		  title: "第1页",
	 		  url
	 		})
	 		for(let i = 2; i <= max; i++){
      chapters.push({
        title: `第${i}页`,
        url: url.replace(".html", `/${i}.html`)
      })
    }
	 }

}else if(/video/.test(baseUrl)){
	 book.type = 4;
	 chapters.push({
	 	  title: book.name,
	 	  url
	 })
}

chapters;

